"use client"

import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog'

interface AuthGateDialogProps {
  open: boolean
  description: string
  onClose: () => void
  onOAuthClick: (provider: 'google' | 'discord' | 'microsoft') => void
}

const OAUTH_PROVIDERS = [
  { key: 'google', label: 'Continue with Google' },
  { key: 'discord', label: 'Continue with Discord' },
  { key: 'microsoft', label: 'Continue with Microsoft' },
] as const

export function AuthGateDialog({ open, description, onClose, onOAuthClick }: AuthGateDialogProps) {
  return (
    <Dialog open={open} onOpenChange={(isOpen) => { if (!isOpen) onClose() }}>
      <DialogContent className="max-w-sm">
        <DialogHeader>
          <DialogTitle>Sign in to continue</DialogTitle>
          <DialogDescription>{description}</DialogDescription>
        </DialogHeader>
        <div className="flex flex-col gap-3 pt-2">
          {OAUTH_PROVIDERS.map((provider, index) => (
            <button
              key={provider.key}
              type="button"
              autoFocus={index === 0}
              onClick={() => onOAuthClick(provider.key)}
              className="flex w-full items-center justify-center gap-2 rounded-md border border-input bg-background px-4 py-2.5 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
            >
              {provider.label}
            </button>
          ))}
        </div>
      </DialogContent>
    </Dialog>
  )
}

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import { AuthGateDialog } from '../AuthGateDialog'

const defaultProps = {
  open: true,
  description: 'Adding Black Lotus to your cart',
  onClose: vi.fn(),
  onOAuthClick: vi.fn(),
}

describe('AuthGateDialog', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  // ── rendering ─────────────────────────────────────────────────────────────

  it('renders the title when open', () => {
    render(<AuthGateDialog {...defaultProps} />)
    expect(screen.getByText('Sign in to continue')).toBeTruthy()
  })

  it('renders the description text when open', () => {
    render(<AuthGateDialog {...defaultProps} />)
    expect(screen.getByText('Adding Black Lotus to your cart')).toBeTruthy()
  })

  it('does not render dialog content when open=false', () => {
    render(<AuthGateDialog {...defaultProps} open={false} />)
    expect(screen.queryByText('Sign in to continue')).toBeNull()
  })

  // ── OAuth buttons ──────────────────────────────────────────────────────────

  it('renders Google, Discord, and Microsoft OAuth buttons', () => {
    render(<AuthGateDialog {...defaultProps} />)
    expect(screen.getByRole('button', { name: /google/i })).toBeTruthy()
    expect(screen.getByRole('button', { name: /discord/i })).toBeTruthy()
    expect(screen.getByRole('button', { name: /microsoft/i })).toBeTruthy()
  })

  it('calls onOAuthClick with "google" when Google button clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    fireEvent.click(screen.getByRole('button', { name: /google/i }))
    expect(defaultProps.onOAuthClick).toHaveBeenCalledWith('google')
  })

  it('calls onOAuthClick with "discord" when Discord button clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    fireEvent.click(screen.getByRole('button', { name: /discord/i }))
    expect(defaultProps.onOAuthClick).toHaveBeenCalledWith('discord')
  })

  it('calls onOAuthClick with "microsoft" when Microsoft button clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    fireEvent.click(screen.getByRole('button', { name: /microsoft/i }))
    expect(defaultProps.onOAuthClick).toHaveBeenCalledWith('microsoft')
  })

  // ── close ──────────────────────────────────────────────────────────────────

  it('calls onClose when the close button is clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    // Radix DialogClose renders an SR label "Close"
    const closeButton = screen.getByRole('button', { name: /close/i })
    fireEvent.click(closeButton)
    expect(defaultProps.onClose).toHaveBeenCalledTimes(1)
  })

  // ── focus ──────────────────────────────────────────────────────────────────

  it('only the first OAuth button has autoFocus (Discord and Microsoft do not)', () => {
    render(<AuthGateDialog {...defaultProps} />)
    // jsdom doesn't reflect React autoFocus as an HTML attribute — we verify
    // that the non-first buttons don't have it set, confirming the prop is applied selectively
    const discordButton = screen.getByRole('button', { name: /discord/i })
    const microsoftButton = screen.getByRole('button', { name: /microsoft/i })
    expect(discordButton).not.toHaveAttribute('autofocus')
    expect(microsoftButton).not.toHaveAttribute('autofocus')
  })
})

"use client"

import { useState } from "react"
import { cn } from "@/lib/utils"
import { OAUTH_PROVIDERS, initiateOAuthLogin, type OAuthProvider } from "@/lib/oauth"

interface SocialLoginButtonsProps {
  returnUrl?: string
  className?: string
  disabled?: boolean
  variant?: "login" | "register" | "link"
  onError?: (error: string) => void
}

// Social provider icons as SVG components
const SocialIcons = {
  Google: () => (
    <svg viewBox="0 0 24 24" className="w-5 h-5">
      <path
        fill="currentColor"
        d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
      />
      <path
        fill="currentColor"
        d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
      />
      <path
        fill="currentColor"
        d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
      />
      <path
        fill="currentColor"
        d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
      />
    </svg>
  ),
  Microsoft: () => (
    <svg viewBox="0 0 24 24" className="w-5 h-5">
      <path fill="#f25022" d="M1 1h10v10H1z" />
      <path fill="#00a4ef" d="M13 1h10v10H13z" />
      <path fill="#7fba00" d="M1 13h10v10H1z" />
      <path fill="#ffb900" d="M13 13h10v10H13z" />
    </svg>
  ),
  Discord: () => (
    <svg viewBox="0 0 24 24" className="w-5 h-5">
      <path
        fill="currentColor"
        d="M20.317 4.37a19.791 19.791 0 00-4.885-1.515.074.074 0 00-.079.037c-.21.375-.444.864-.608 1.25a18.27 18.27 0 00-5.487 0 12.64 12.64 0 00-.617-1.25.077.077 0 00-.079-.037A19.736 19.736 0 003.677 4.37a.07.07 0 00-.032.027C.533 9.046-.32 13.58.099 18.057a.082.082 0 00.031.057 19.9 19.9 0 005.993 3.03.078.078 0 00.084-.028c.462-.63.874-1.295 1.226-1.994a.076.076 0 00-.041-.106 13.107 13.107 0 01-1.872-.892.077.077 0 01-.008-.128 10.2 10.2 0 00.372-.292.074.074 0 01.077-.01c3.928 1.793 8.18 1.793 12.062 0a.074.074 0 01.078.01c.12.098.246.198.373.292a.077.077 0 01-.006.127 12.299 12.299 0 01-1.873.892.077.077 0 00-.041.107c.36.698.772 1.362 1.225 1.993a.076.076 0 00.084.028 19.839 19.839 0 006.002-3.03.077.077 0 00.032-.054c.5-5.177-.838-9.674-3.549-13.66a.061.061 0 00-.031-.03zM8.02 15.33c-1.183 0-2.157-1.085-2.157-2.419 0-1.333.956-2.419 2.157-2.419 1.21 0 2.176 1.096 2.157 2.42 0 1.333-.956 2.418-2.157 2.418zm7.975 0c-1.183 0-2.157-1.085-2.157-2.419 0-1.333.956-2.419 2.157-2.419 1.21 0 2.176 1.096 2.157 2.42 0 1.333-.946 2.418-2.157 2.418z"
      />
    </svg>
  ),
}

const PROVIDER_STYLES: Record<string, string> = {
  google:
    "bg-white text-[#1f1f1f] border-[rgba(255,255,255,0.12)] hover:bg-[#f8f8f8] shadow-[0_1px_3px_rgba(0,0,0,0.08)]",
  discord:
    "bg-[#5865F2] text-white border-[rgba(88,101,242,0.3)] hover:bg-[#4752C4] shadow-[0_1px_3px_rgba(88,101,242,0.2)]",
  microsoft:
    "bg-[#2F2F2F] text-white border-[rgba(255,255,255,0.08)] hover:bg-[#3a3a3a] shadow-[0_1px_3px_rgba(0,0,0,0.12)]",
}

const SocialButton: React.FC<{
  provider: OAuthProvider
  onClick: () => void
  disabled: boolean
  variant: string
}> = ({ provider, onClick, disabled, variant }) => {
  const config = OAUTH_PROVIDERS[provider]
  const Icon = SocialIcons[config.icon as keyof typeof SocialIcons]

  const getButtonText = () => {
    switch (variant) {
      case "register":
        return `Sign up with ${config.name}`
      case "link":
        return `Link ${config.name}`
      default:
        return `Continue with ${config.name}`
    }
  }

  return (
    <button
      className={cn(
        "w-full flex items-center justify-center gap-3 h-12 text-sm font-medium rounded-[14px] border transition-colors disabled:opacity-50",
        PROVIDER_STYLES[provider] ?? ""
      )}
      onClick={onClick}
      disabled={disabled}
    >
      <Icon />
      <span>{getButtonText()}</span>
    </button>
  )
}

export const SocialLoginButtons: React.FC<SocialLoginButtonsProps> = ({
  returnUrl,
  className = "",
  disabled = false,
  variant = "login",
  onError,
}) => {
  const [loadingProvider, setLoadingProvider] = useState<OAuthProvider | null>(null)

  const handleSocialLogin = async (provider: OAuthProvider) => {
    if (disabled || loadingProvider) return

    try {
      setLoadingProvider(provider)
      await initiateOAuthLogin(provider, returnUrl)
    } catch (error: any) {
      console.error(`${provider} login error:`, error)
      onError?.(error.message || `Failed to initiate ${provider} login`)
      setLoadingProvider(null)
    }
  }

  const providers: OAuthProvider[] = ["google", "discord", "microsoft"]

  return (
    <div className={cn("space-y-3", className)}>
      <div className="grid grid-cols-1 gap-3">
        {providers.map((provider) => (
          <SocialButton
            key={provider}
            provider={provider}
            onClick={() => handleSocialLogin(provider)}
            disabled={disabled || loadingProvider === provider}
            variant={variant}
          />
        ))}
      </div>

      {loadingProvider && (
        <div className="text-center text-sm text-secondary">
          Redirecting to {OAUTH_PROVIDERS[loadingProvider].name}...
        </div>
      )}
    </div>
  )
}

