import { useState, useEffect } from 'react';

export const useScreenSize = () => {
  const [screenSize, setScreenSize] = useState<
    'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | ''
  >('');

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 640) {
        setScreenSize('xs');
      } else if (
        window.innerWidth >= 640 &&
        window.innerWidth < 768
      ) {
        setScreenSize('sm');
      } else if (
        window.innerWidth >= 768 &&
        window.innerWidth < 1024
      ) {
        setScreenSize('md');
      } else if (
        window.innerWidth >= 1024 &&
        window.innerWidth < 1280
      ) {
        setScreenSize('lg');
      } else if (
        window.innerWidth >= 1280 &&
        window.innerWidth < 1536
      ) {
        setScreenSize('xl');
      } else if (window.innerWidth >= 1536) {
        setScreenSize('2xl');
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize();

    return () =>
      window.removeEventListener('resize', handleResize);
  }, []);

  return screenSize;
};

"use client"

import { useState } from 'react'
import { saveIntent, setReturnUrlCookie, type DeferredAction } from '@/lib/deferred-intent'

export interface AuthGateOptions {
  action: string
  payload?: unknown
  description: string
  returnUrl?: string
}

function isAuthenticated(): boolean {
  if (typeof document === 'undefined') return false
  return document.cookie.split('; ').some((row) => row.startsWith('_medusa_jwt='))
}

export function useAuthGate() {
  const [open, setOpen] = useState(false)
  const [pendingIntent, setPendingIntent] = useState<DeferredAction | null>(null)

  const triggerAuthGate = (options: AuthGateOptions) => {
    if (isAuthenticated()) {
      return
    }

    const returnUrl = options.returnUrl ?? window.location.pathname
    const intent: DeferredAction = {
      action: options.action,
      payload: options.payload ?? null,
      description: options.description,
      returnUrl,
      timestamp: Date.now(),
    }

    setPendingIntent(intent)
    setOpen(true)
  }

  const onClose = () => {
    setOpen(false)
    setPendingIntent(null)
  }

  const onOAuthClick = (provider: 'google' | 'discord' | 'microsoft') => {
    if (pendingIntent) {
      saveIntent(pendingIntent)
      setReturnUrlCookie(pendingIntent.returnUrl)
    }
    window.location.href = `/auth/customer/${provider}`
  }

  return {
    isAuthenticated: isAuthenticated(),
    triggerAuthGate,
    dialogProps: {
      open,
      description: pendingIntent?.description ?? '',
      onClose,
      onOAuthClick,
    },
  }
}

"use client"

import * as React from "react"
import * as DialogPrimitive from "@radix-ui/react-dialog"
import { X } from "lucide-react"

import { cn } from "@/lib/utils"

