import { MedusaRequest, MedusaResponse } from '@medusajs/framework/http'
import {
  Modules,
  MedusaError
} from '@medusajs/framework/utils'

/**
 * Initiates OAuth authentication flow for customers
 */
export const GET = async (req: MedusaRequest, res: MedusaResponse) => {
  const { auth_provider } = req.params
  const authService = req.scope.resolve(Modules.AUTH)
  
  console.log(`Initiating OAuth for provider: ${auth_provider}`)

  const authData = {
    url: req.url,
    headers: req.headers as Record<string, string>,
    query: req.query as Record<string, string>,
    body: req.body as Record<string, string> | undefined,
    protocol: req.protocol,
  }

  try {
    // Initiate OAuth flow
    const { success, error, location } = await authService.authenticate(
      auth_provider,
      authData
    )

    if (location) {
      console.log(`Redirecting to OAuth provider: ${location}`)
      return res.status(200).json({ location })
    }

    if (!success) {
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        error || 'Failed to initiate authentication'
      )
    }

    // Should not reach here for OAuth providers
    throw new MedusaError(
      MedusaError.Types.INVALID_DATA,
      'Invalid OAuth flow'
    )
  } catch (error) {
    console.error('OAuth initiation error:', error)
    throw error
  }
}

export const POST = async (req: MedusaRequest, res: MedusaResponse) => {
  return GET(req, res)
}

import { MedusaStoreRequest, MedusaResponse } from '@medusajs/framework/http'
import {
  ContainerRegistrationKeys,
  Modules,
  MedusaError
} from '@medusajs/framework/utils'
import { generateJwtToken } from '@medusajs/framework/utils'
import { EMAIL_VERIFICATION_MODULE } from '#/modules/email-verification'
import EmailVerificationService from '#/modules/email-verification/service'
import { AUTHENTICATION_MODULE } from '#/modules/authentication'
import SocialAccountManagementService from '#/modules/authentication/services/social-account-management.service'
import { emitAuthEvent, AuthEventType } from '#/modules/authentication/services/auth-event-emitter'

// Type definitions for auth identity
interface AuthIdentityMetadata {
  email?: string
  name?: string
  given_name?: string
  family_name?: string
  picture?: string
  avatar_url?: string
}

interface AuthIdentity {
  id: string
  entity_id?: string
  provider_identities?: any[]
  app_metadata?: Record<string, any>
  metadata?: AuthIdentityMetadata
}

/**
 * Custom OAuth callback handler for customer authentication
 * Creates or links customers to auth identities and generates proper JWT tokens
 */
export const GET = async (req: MedusaStoreRequest, res: MedusaResponse) => {
  const { auth_provider } = req.params
  const config = req.scope.resolve(ContainerRegistrationKeys.CONFIG_MODULE)
  const authService = req.scope.resolve(Modules.AUTH)
  const customerService = req.scope.resolve(Modules.CUSTOMER)

  console.log(`OAuth callback for provider: ${auth_provider}`)
  console.log(`Query params:`, req.query)

  const authData = {
    url: req.url,
    headers: req.headers as Record<string, string>,
    query: req.query as Record<string, string>,
    body: req.body as Record<string, string> | undefined,
    protocol: req.protocol,
  }

  try {
    // Validate the OAuth callback
    const result = await authService.validateCallback(
      auth_provider,
      authData
    )

    const { success, error } = result
    const authIdentity = result.authIdentity as AuthIdentity

    if (!success || !authIdentity) {
      console.error('OAuth validation failed:', error)
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        error || 'Authentication failed'
      )
    }

    console.log('Auth identity validated:', {
      id: authIdentity.id,
      entity_id: authIdentity.entity_id,
      provider: auth_provider,
      metadata: authIdentity.metadata,
      app_metadata: authIdentity.app_metadata,
      provider_identities: authIdentity.provider_identities
    })

    // Extract email from provider identities (where Google stores user data)
    const providerIdentity = authIdentity.provider_identities?.[0]
    const userMetadata = providerIdentity?.user_metadata || {}
    const email = userMetadata.email ||
                  authIdentity.metadata?.email ||
                  authIdentity.app_metadata?.email ||
                  (authIdentity as any).user_metadata?.email
    if (!email) {
      console.error('Failed to extract email from auth identity:', {
        id: authIdentity.id,
        allFields: JSON.stringify(authIdentity, null, 2)
      })
      throw new MedusaError(
        MedusaError.Types.INVALID_DATA,
        'Email not provided by OAuth provider'
      )
    }

    console.log('Extracted email:', email)

    let customer

    // Check if auth identity already has a linked customer
    if (authIdentity.app_metadata?.customer_id) {
      console.log('Auth identity already linked to customer:', authIdentity.app_metadata.customer_id)
      try {
        customer = await customerService.retrieveCustomer(
          authIdentity.app_metadata.customer_id as string,
          {}
        )
      } catch (err) {
        console.error('Failed to retrieve linked customer:', err)
        // Customer was deleted or doesn't exist, will create new one
      }
    }

    // If no linked customer, try to find or create one
    if (!customer) {
      console.log('Looking for existing customer with email:', email)

      // Try to find existing customer by email
      const [existingCustomer] = await customerService.listCustomers(
        { email },
        {}
      )

      if (existingCustomer) {
        console.log('Found existing customer:', existingCustomer.id)
        customer = existingCustomer
      } else {
        console.log('Creating new customer for email:', email)
        // Create new customer
        customer = await customerService.createCustomers({
          email,
          first_name: userMetadata.given_name ||
                      userMetadata.name?.split(' ')[0] || '',
          last_name: userMetadata.family_name ||
                     userMetadata.name?.split(' ').slice(1).join(' ') || '',
          metadata: {
            auth_provider: auth_provider,
            oauth_registered: true,
            avatar_url: userMetadata.picture ||
                       userMetadata.avatar_url
          }
        })
        console.log('Created new customer:', customer.id)
      }

      // Update auth identity with customer_id in app_metadata
      console.log('Updating auth identity with customer_id:', customer.id)
      await authService.updateAuthIdentities({
        id: authIdentity.id,
        app_metadata: {
          ...authIdentity.app_metadata,
          customer_id: customer.id
        }
      })
    }

    // Auto-verify email for social OAuth customers (provider has already verified the email)
    const emailVerificationService = req.scope.resolve<EmailVerificationService>(EMAIL_VERIFICATION_MODULE)
    await emailVerificationService.autoVerifyEmail(customer.id)

    // Generate refresh token and look up platform_role concurrently
    // platform_role is re-read from DB on every login — never cached from old token
    const authModuleService = req.scope.resolve<SocialAccountManagementService>(AUTHENTICATION_MODULE)
    const [{ rawToken: refreshToken }, platformRole] = await Promise.all([
      authModuleService.generateRefreshToken(customer.id, {
        ipAddress: (req.headers['x-forwarded-for'] as string) || req.ip,
        userAgent: req.headers['user-agent'] as string
      }),
      authModuleService.getCustomerPlatformRole(customer.id)
    ])

    // Generate short-lived JWT access token (15 minutes)
    const { http } = config.projectConfig
    const accessToken = generateJwtToken(
      {
        actor_id: customer.id,
        actor_type: 'customer',
        auth_identity_id: authIdentity.id,
        app_metadata: {
          customer_id: customer.id,
          platform_role: platformRole
        }
      },
      {
        secret: http.jwtSecret,
        expiresIn: '15m'
      }
    )

    // Emit LOGIN auth event (fire-and-forget)
    emitAuthEvent({
      customer_id: customer.id,
      event_type: AuthEventType.LOGIN,
      ip_address: (req.headers['x-forwarded-for'] as string) || req.ip,
      user_agent: req.headers['user-agent'] as string,
      metadata: { provider: auth_provider }
    })

    // Set refresh token as httpOnly cookie before redirect (avoids leaking in URL)
    const isProduction = process.env.NODE_ENV === 'production'
    res.cookie('_medusa_refresh', refreshToken, {
      httpOnly: true,
      secure: isProduction,
      sameSite: 'strict',
      maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
      path: '/'
    })

    // Redirect to storefront callback with access token only
    const redirectUrl = process.env.STOREFRONT_URL || 'http://localhost:3000'
    const callbackUrl = `${redirectUrl}/auth/callback?token=${accessToken}`

    return res.redirect(callbackUrl)
  } catch (error) {
    console.error('OAuth callback error:', error)

    const redirectUrl = process.env.STOREFRONT_URL || 'http://localhost:3000'
    const errorUrl = `${redirectUrl}/auth/error?message=${encodeURIComponent(error.message || 'Authentication failed')}`

    return res.redirect(errorUrl)
  }
}

export const POST = async (req: MedusaStoreRequest, res: MedusaResponse) => {
  return GET(req, res)
}

