export function AuthBottomSheet({
  open,
  description,
  onClose,
  onOAuthClick,
}: AuthBottomSheetProps) {
  const [visible, setVisible] = useState(false)

  useEffect(() => {
    if (open) {
      // Small delay to trigger CSS transition
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setVisible(true))
      })
    } else {
      setVisible(false)
    }
  }, [open])

  if (!open) return null

  return (
    <div className="fixed inset-0 z-50 md:hidden" role="dialog" aria-modal="true">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-[rgba(9,9,15,0.75)] transition-opacity duration-300"
        style={{ opacity: visible ? 1 : 0 }}
        onClick={onClose}
        data-testid="bottom-sheet-backdrop"
      />

      {/* Bottom sheet */}
      <div
        className="absolute bottom-0 left-0 right-0 z-20 rounded-t-[20px] border border-b-0 border-[var(--border-strong,#4A4680)] px-6 pb-9 pt-3 transition-transform duration-[350ms] ease-out"
        style={{
          background:
            "linear-gradient(180deg, var(--bg-surface-2, #21203A) 0%, var(--bg-surface-1, #18162A) 100%)",
          boxShadow: "0 -16px 60px rgba(0, 0, 0, 0.5)",
          transform: visible ? "translateY(0)" : "translateY(100%)",
        }}
        data-testid="bottom-sheet"
      >
        {/* Handle bar */}
        <div
          className="mx-auto mb-5 h-1 w-10 rounded-full bg-surface-4"
          data-testid="bottom-sheet-handle"
        />

        {/* Gradient icon */}
        <div
          className="mb-3.5 flex h-10 w-10 items-center justify-center rounded-[12px] border border-[rgba(139,92,246,0.2)]"
          style={{
            background:
              "linear-gradient(135deg, rgba(139,92,246,0.2), rgba(255,120,73,0.1))",
          }}
          data-testid="gradient-icon"
        >
          <Lock className="h-[18px] w-[18px] text-[var(--brand-primary,#8B5CF6)]" />
        </div>

        {/* Heading */}
        <h2 className="mb-1.5 font-display text-[22px] font-bold tracking-[0.02em] text-[var(--text-primary,#F0EEFF)]">
          Sign in to continue
        </h2>

        {/* Description */}
        <p className="mb-5 font-sans text-[13px] leading-[1.6] text-[var(--text-secondary,#B8B0D8)]">
          {description}
        </p>

        {/* OAuth buttons */}
        <div className="mb-3 flex flex-col gap-2.5">
          {OAUTH_PROVIDERS.map((provider) => (
            <button
              key={provider.key}
              type="button"
              onClick={() => onOAuthClick(provider.key)}
              className={`flex h-[42px] w-full items-center justify-center gap-3 rounded-[12px] text-[13px] font-semibold transition-colors ${provider.className}`}
            >
              {provider.icon}
              {provider.label}
            </button>
          ))}
        </div>

        {/* Continue as guest */}
        <button
          type="button"
          onClick={onClose}
          className="mt-1 flex h-[42px] w-full items-center justify-center rounded-[12px] border border-[var(--border-default,#2C2A4A)] bg-transparent text-[13px] font-medium text-[var(--text-secondary,#B8B0D8)] transition-colors hover:bg-[var(--bg-surface-3,#2C2A4A)]"
        >
          Continue as Guest
        </button>
      </div>
    </div>
  )
}

