import { describe, it, expect, vi, beforeEach } from "vitest"
import { render, screen, fireEvent, within } from "@testing-library/react"
import { AuthGateDialog } from "../AuthGateDialog"

/**
 * Backend OAuth Verification (T02 Step 4)
 *
 * Google auth provider:
 *   - Registered in backend/apps/backend/medusa-config.ts (line ~33)
 *   - Module: @medusajs/medusa/auth-google, id: 'google'
 *   - Env vars: GOOGLE_CLIENT_ID, GOOGLE_CLIENT_SECRET
 *
 * Discord auth provider:
 *   - Registered in backend/apps/backend/medusa-config.ts (line ~42)
 *   - Module: ./src/modules/discord-auth, id: 'discord'
 *   - Env vars: DISCORD_CLIENT_ID, DISCORD_CLIENT_SECRET, DISCORD_CALLBACK_URL
 *   - Implementation: backend/apps/backend/src/modules/discord-auth/services/discord.ts
 *
 * Generic callback route:
 *   - backend/apps/backend/src/api/auth/customer/[auth_provider]/callback/route.ts
 *   - Handles both Google and Discord via dynamic [auth_provider] param
 *   - Creates/links customers, generates JWT, sets refresh cookie, redirects to storefront
 */

const defaultProps = {
  open: true,
  description: "Adding Black Lotus to your cart",
  onClose: vi.fn(),
  onOAuthClick: vi.fn(),
}

// Mock matchMedia for jsdom (needed since components use responsive CSS)
beforeEach(() => {
  Object.defineProperty(window, "matchMedia", {
    writable: true,
    value: vi.fn().mockImplementation((query: string) => ({
      matches: false,
      media: query,
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
  })
})

describe("AuthGateDialog", () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  // ── rendering ─────────────────────────────────────────────────────────────

  it("renders the heading when open", () => {
    render(<AuthGateDialog {...defaultProps} />)
    const headings = screen.getAllByText("Sign in to continue")
    expect(headings.length).toBeGreaterThanOrEqual(1)
  })

  it("renders the description text when open", () => {
    render(<AuthGateDialog {...defaultProps} />)
    const descriptions = screen.getAllByText("Adding Black Lotus to your cart")
    expect(descriptions.length).toBeGreaterThanOrEqual(1)
  })

  it("does not render dialog content when open=false", () => {
    render(<AuthGateDialog {...defaultProps} open={false} />)
    expect(screen.queryByText("Sign in to continue")).toBeNull()
  })

  // ── gradient icon ─────────────────────────────────────────────────────────

  it("renders gradient icon", () => {
    render(<AuthGateDialog {...defaultProps} />)
    const icons = screen.getAllByTestId("gradient-icon")
    expect(icons.length).toBeGreaterThanOrEqual(1)
  })

  // ── OAuth buttons ─────────────────────────────────────────────────────────

  it("renders Google, Discord, and Microsoft OAuth buttons", () => {
    render(<AuthGateDialog {...defaultProps} />)
    // Both desktop and mobile render buttons, so there should be multiples
    expect(screen.getAllByRole("button", { name: /google/i }).length).toBeGreaterThanOrEqual(1)
    expect(screen.getAllByRole("button", { name: /discord/i }).length).toBeGreaterThanOrEqual(1)
    expect(screen.getAllByRole("button", { name: /microsoft/i }).length).toBeGreaterThanOrEqual(1)
  })

  it("renders 3 OAuth buttons with correct labels", () => {
    render(<AuthGateDialog {...defaultProps} />)
    expect(screen.getAllByText("Continue with Google").length).toBeGreaterThanOrEqual(1)
    expect(screen.getAllByText("Continue with Discord").length).toBeGreaterThanOrEqual(1)
    expect(screen.getAllByText("Continue with Microsoft").length).toBeGreaterThanOrEqual(1)
  })

  it('calls onOAuthClick with "google" when Google button clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    const buttons = screen.getAllByRole("button", { name: /google/i })
    fireEvent.click(buttons[0])
    expect(defaultProps.onOAuthClick).toHaveBeenCalledWith("google")
  })

  it('calls onOAuthClick with "discord" when Discord button clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    const buttons = screen.getAllByRole("button", { name: /discord/i })
    fireEvent.click(buttons[0])
    expect(defaultProps.onOAuthClick).toHaveBeenCalledWith("discord")
  })

  it('calls onOAuthClick with "microsoft" when Microsoft button clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    const buttons = screen.getAllByRole("button", { name: /microsoft/i })
    fireEvent.click(buttons[0])
    expect(defaultProps.onOAuthClick).toHaveBeenCalledWith("microsoft")
  })

  // ── close ─────────────────────────────────────────────────────────────────

  it("calls onClose when the close button is clicked", () => {
    render(<AuthGateDialog {...defaultProps} />)
    // Desktop Dialog has a close button with aria-label="Close"
    const closeButton = screen.getByRole("button", { name: /^close$/i })
    fireEvent.click(closeButton)
    expect(defaultProps.onClose).toHaveBeenCalledTimes(1)
  })

  // ── Continue as Guest ─────────────────────────────────────────────────────

  it('renders "Continue as Guest" button', () => {
    render(<AuthGateDialog {...defaultProps} />)
    const guestButtons = screen.getAllByRole("button", { name: /continue as guest/i })
    expect(guestButtons.length).toBeGreaterThanOrEqual(1)
  })

  it('calls onClose when "Continue as Guest" is clicked', () => {
    render(<AuthGateDialog {...defaultProps} />)
    const guestButtons = screen.getAllByRole("button", { name: /continue as guest/i })
    fireEvent.click(guestButtons[0])
    expect(defaultProps.onClose).toHaveBeenCalled()
  })

  // ── description with <strong> ─────────────────────────────────────────────

  it("renders description containing <strong> content", () => {
    render(
      <AuthGateDialog
        {...defaultProps}
        description={
          <span>
            Your deck <strong>Mono Red Burn</strong> is ready
          </span>
        }
      />
    )
    const strongElements = screen.getAllByText("Mono Red Burn")
    expect(strongElements.length).toBeGreaterThanOrEqual(1)
    expect(strongElements[0].tagName).toBe("STRONG")
  })

  // ── bottom sheet (mobile) ─────────────────────────────────────────────────

  it("renders bottom sheet handle bar for mobile", () => {
    render(<AuthGateDialog {...defaultProps} />)
    const handles = screen.getAllByTestId("bottom-sheet-handle")
    expect(handles.length).toBeGreaterThanOrEqual(1)
  })

  it("renders bottom sheet with backdrop for mobile", () => {
    render(<AuthGateDialog {...defaultProps} />)
    const backdrops = screen.getAllByTestId("bottom-sheet-backdrop")
    expect(backdrops.length).toBeGreaterThanOrEqual(1)
  })
})

